//! ZCL compliance harness
//!
//! Run: `cargo test --test zcl_compliance`
//!
//! The harness loads byte fixtures from `vectors/zcl_data_types.json`.
//! Fixtures are generated by `scripts/gen_vectors.py` using zigpy as the
//! reference implementation. Normal Rust tests do not require Python or zigpy.
//!
//! ## Fixture conventions
//!
//! | Field            | Used by                                      |
//! |------------------|----------------------------------------------|
//! | `roundtrip`      | scalars, enums, strings, collections, struct |
//! | `roundtrip_bits` | f32, f64 (NaN-safe bit repr)                 |
//! | `roundtrip_raw`  | bitmaps (raw primitive repr)                 |
//! | `null_wire`      | all nullable types                           |
//! | `type_mismatch`  | typed collections                            |
//! | `invalid`        | malformed collection and struct wires        |
//! | `valid`          | set collections                              |
//! | `duplicate`      | set collections                              |
//! | `invalid_value`  | bool invalid non-null values                 |
//! | `invalid_utf8`   | short_text                                   |

use std::collections::BTreeMap;
use std::sync::LazyLock;

use serde::Deserialize;
use serde::de::DeserializeOwned;
use serde_json::Value;
use zigbee_cluster_library::types::Array;
use zigbee_cluster_library::types::ArrayOf;
use zigbee_cluster_library::types::ArrayRef;
use zigbee_cluster_library::types::Bag;
use zigbee_cluster_library::types::BagOf;
use zigbee_cluster_library::types::Bitmap8;
use zigbee_cluster_library::types::Bitmap16;
use zigbee_cluster_library::types::Bitmap32;
use zigbee_cluster_library::types::Bitmap64;
use zigbee_cluster_library::types::CollectionEncoder;
use zigbee_cluster_library::types::Enum8;
use zigbee_cluster_library::types::Enum16;
use zigbee_cluster_library::types::Nullable;
use zigbee_cluster_library::types::RawUniqueSet;
use zigbee_cluster_library::types::Set;
use zigbee_cluster_library::types::SetOf;
use zigbee_cluster_library::types::ShortOctetString;
use zigbee_cluster_library::types::ShortStr;
use zigbee_cluster_library::types::ShortText;
use zigbee_cluster_library::types::StructDecoder;
use zigbee_cluster_library::types::StructEncoder;
use zigbee_cluster_library::types::StructOf;
use zigbee_cluster_library::types::TypeId;
use zigbee_cluster_library::types::ZclBitmap8;
use zigbee_cluster_library::types::ZclBitmap16;
use zigbee_cluster_library::types::ZclBitmap32;
use zigbee_cluster_library::types::ZclBitmap64;
use zigbee_cluster_library::types::ZclEnum8;
use zigbee_cluster_library::types::ZclEnum16;
use zigbee_cluster_library::types::ZclError;
use zigbee_cluster_library::types::ZclHasNull;
use zigbee_cluster_library::types::ZclSchema;
use zigbee_cluster_library::types::ZclStructSchema;
use zigbee_cluster_library::types::ZclValueRef;

#[derive(Debug, Deserialize)]
struct FixtureFile {
    schema_version: u32,
    source: FixtureSource,
    types: BTreeMap<String, TypeFixture>,
}

#[derive(Debug, Deserialize)]
struct FixtureSource {
    generator: String,
    zigpy: String,
}

#[derive(Debug, Deserialize)]
struct TypeFixture {
    type_id: u8,
    #[serde(default)]
    roundtrip: Vec<Case>,
    #[serde(default)]
    roundtrip_bits: Vec<Case>,
    #[serde(default)]
    roundtrip_raw: Vec<Case>,
    #[serde(default)]
    null_wire: Vec<WireCase>,
    #[serde(default)]
    type_mismatch: Vec<TypeMismatchCase>,
    #[serde(default)]
    invalid: Vec<InvalidCase>,
    #[serde(default)]
    valid: Vec<Case>,
    #[serde(default)]
    duplicate: Vec<WireCase>,
    #[serde(default)]
    invalid_value: Vec<WireCase>,
    #[serde(default)]
    invalid_utf8: Vec<WireCase>,
}

#[derive(Debug, Deserialize)]
struct WireCase {
    name: String,
    wire: String,
}

#[derive(Debug, Deserialize)]
struct TypeMismatchCase {
    name: String,
    wire: String,
    expected: u8,
    found: u8,
}

#[derive(Debug, Deserialize)]
struct InvalidCase {
    name: String,
    wire: String,
    error: String,
    #[serde(default)]
    expected: Option<u8>,
    #[serde(default)]
    found: Option<u8>,
}

#[derive(Debug, Deserialize)]
struct Case {
    name: String,
    wire: String,
    #[serde(default)]
    value: Value,
    #[serde(default)]
    values: Vec<Value>,
    #[serde(default)]
    value_hex: Option<String>,
    #[serde(default)]
    bits: Option<u64>,
    #[serde(default)]
    inner_wires: Vec<String>,
}

static FIXTURES: LazyLock<FixtureFile> = LazyLock::new(|| {
    let parsed: FixtureFile = serde_json::from_str(include_str!("vectors/zcl_data_types.json"))
        .expect("zcl_data_types.json fixture should parse");
    assert_eq!(parsed.schema_version, 1, "fixture schema version changed");
    assert_eq!(parsed.source.generator, "scripts/gen_vectors.py");
    assert!(!parsed.source.zigpy.is_empty(), "zigpy version missing");
    parsed
});

fn fixture(name: &str) -> &'static TypeFixture {
    FIXTURES
        .types
        .get(name)
        .unwrap_or_else(|| panic!("fixture {name:?} missing"))
}

fn parse_wire(encoded: &str) -> Vec<u8> {
    let compact = encoded.split_whitespace().collect::<String>();
    assert_eq!(compact.len() % 2, 0, "odd-length hex wire: {encoded}");
    (0..compact.len())
        .step_by(2)
        .map(|i| u8::from_str_radix(&compact[i..i + 2], 16).expect("fixture hex byte"))
        .collect()
}

fn wire_case(case: &WireCase) -> Vec<u8> {
    parse_wire(&case.wire)
}

fn type_mismatch_wire(case: &TypeMismatchCase) -> Vec<u8> {
    parse_wire(&case.wire)
}

fn invalid_wire(case: &InvalidCase) -> Vec<u8> {
    parse_wire(&case.wire)
}

fn case_wire(case: &Case) -> Vec<u8> {
    parse_wire(&case.wire)
}

fn type_id(raw: u8) -> TypeId {
    TypeId::from_u8(raw)
}

fn dynamic_roundtrip_cases(fixture: &TypeFixture) -> impl Iterator<Item = &Case> {
    fixture
        .roundtrip
        .iter()
        .chain(&fixture.roundtrip_bits)
        .chain(&fixture.roundtrip_raw)
        .chain(&fixture.valid)
}

fn dynamic_null_supported(type_id: TypeId) -> bool {
    matches!(
        type_id,
        TypeId::CharacterString
            | TypeId::OctetString
            | TypeId::Array
            | TypeId::Set
            | TypeId::Bag
            | TypeId::Structure
    )
}

fn assert_dynamic_value_roundtrip(type_id: TypeId, wire: &[u8], context: &str) {
    let (value, n) = ZclValueRef::decode_with_type(type_id, wire)
        .unwrap_or_else(|e| panic!("{context} dynamic decode → {e:?}"));
    assert_eq!(n, wire.len(), "{context} dynamic decode consumed");
    assert_eq!(value.type_id(), type_id, "{context} dynamic type id");
    assert_eq!(value.encoded_len(), wire.len(), "{context} encoded len");

    let mut buf = vec![0u8; wire.len()];
    let written = value
        .encode(&mut buf)
        .unwrap_or_else(|e| panic!("{context} dynamic encode → {e:?}"));
    assert_eq!(written, wire.len(), "{context} dynamic encode len");
    assert_eq!(buf.as_slice(), wire, "{context} dynamic encode wire");
}

fn assert_type_mismatch(actual: ZclError, expected: u8, found: u8, context: &str) {
    assert_eq!(
        actual,
        ZclError::TypeIdMismatch {
            expected: type_id(expected),
            found: type_id(found),
        },
        "{context}",
    );
}

fn assert_zcl_error(actual: ZclError, case: &InvalidCase, context: &str) {
    match case.error.as_str() {
        "InsufficientBytes" => assert_eq!(actual, ZclError::InsufficientBytes, "{context}"),
        "InvalidLength" => assert_eq!(actual, ZclError::InvalidLength, "{context}"),
        "InvalidValue" => assert_eq!(actual, ZclError::InvalidValue, "{context}"),
        "InvalidUtf8" => assert_eq!(actual, ZclError::InvalidUtf8, "{context}"),
        "NullSentinel" => assert_eq!(actual, ZclError::NullSentinel, "{context}"),
        "UnconsumedData" => assert_eq!(actual, ZclError::UnconsumedData, "{context}"),
        "TypeIdMismatch" => assert_type_mismatch(
            actual,
            case.expected
                .unwrap_or_else(|| panic!("{context}: missing expected type id")),
            case.found
                .unwrap_or_else(|| panic!("{context}: missing found type id")),
            context,
        ),
        other => panic!("{context}: unknown expected error {other}"),
    }
}

fn assert_type_mismatch_case(actual: ZclError, case: &TypeMismatchCase, context: &str) {
    assert_type_mismatch(actual, case.expected, case.found, context);
}

fn case_value<T: DeserializeOwned>(case: &Case) -> T {
    serde_json::from_value(case.value.clone())
        .unwrap_or_else(|e| panic!("{} value does not match expected type: {e}", case.name))
}

fn case_values<T: DeserializeOwned>(case: &Case) -> Vec<T> {
    case.values
        .iter()
        .cloned()
        .map(|value| {
            serde_json::from_value(value).unwrap_or_else(|e| {
                panic!("{} element does not match expected type: {e}", case.name)
            })
        })
        .collect()
}

fn case_bytes(case: &Case) -> Vec<u8> {
    parse_wire(
        case.value_hex
            .as_deref()
            .unwrap_or_else(|| panic!("{} missing value_hex", case.name)),
    )
}

fn case_bits_u32(case: &Case) -> u32 {
    case.bits
        .unwrap_or_else(|| panic!("{} missing bits", case.name))
        .try_into()
        .unwrap_or_else(|_| panic!("{} bits do not fit u32", case.name))
}

fn case_bits_u64(case: &Case) -> u64 {
    case.bits
        .unwrap_or_else(|| panic!("{} missing bits", case.name))
}

fn value_pair(value: &Value) -> (u8, u16) {
    let pair = value.as_array().expect("pair value should be array");
    assert_eq!(pair.len(), 2, "pair should have two fields");
    let first = serde_json::from_value(pair[0].clone()).expect("pair u8");
    let second = serde_json::from_value(pair[1].clone()).expect("pair u16");
    (first, second)
}

fn case_pair(case: &Case) -> (u8, u16) {
    value_pair(&case.value)
}

fn case_pairs(case: &Case) -> Vec<(u8, u16)> {
    case.values.iter().map(value_pair).collect()
}

fn case_struct_with_array(case: &Case) -> (u8, Vec<u8>) {
    let object = case
        .value
        .as_object()
        .expect("struct value should be object");
    let u8_value = serde_json::from_value(object["u8"].clone()).expect("struct u8 field");
    let array = serde_json::from_value(object["array"].clone()).expect("struct array field");
    (u8_value, array)
}

fn decode_err<S: ZclSchema>(wire: &[u8], context: &str) -> ZclError {
    match S::decode(wire) {
        Ok(_) => panic!("{context}: decode unexpectedly succeeded"),
        Err(err) => err,
    }
}

fn nullable_decode_err<S: ZclHasNull>(wire: &[u8], context: &str) -> ZclError {
    match Nullable::<S>::decode(wire) {
        Ok(_) => panic!("{context}: Nullable decode unexpectedly succeeded"),
        Err(err) => err,
    }
}

fn assert_null_wire_rejected<S: ZclSchema>(fixture_name: &str) {
    let fixture = fixture(fixture_name);
    for case in &fixture.null_wire {
        let wire = wire_case(case);
        assert_eq!(
            decode_err::<S>(&wire, &format!("{fixture_name}/{}", case.name)),
            ZclError::NullSentinel,
            "{fixture_name}/{}",
            case.name,
        );
    }
}

fn assert_nullable_none_decode<S: ZclHasNull>(fixture_name: &str) {
    let fixture = fixture(fixture_name);
    for case in &fixture.null_wire {
        let wire = wire_case(case);
        let (val, n) = Nullable::<S>::decode(&wire)
            .unwrap_or_else(|e| panic!("{fixture_name}/{} Nullable decode → {e:?}", case.name));
        assert!(val.is_none(), "{fixture_name}/{}", case.name);
        assert_eq!(n, wire.len(), "{fixture_name}/{}", case.name);
    }
}

fn assert_nullable_none_encode<S: ZclHasNull>(fixture_name: &str, buf: &mut [u8]) {
    let fixture = fixture(fixture_name);
    for case in &fixture.null_wire {
        let wire = wire_case(case);
        let n = Nullable::<S>::encode(None, buf).unwrap_or_else(|e| {
            panic!("{fixture_name}/{} Nullable encode None → {e:?}", case.name)
        });
        assert_eq!(&buf[..n], wire.as_slice(), "{fixture_name}/{}", case.name);
    }
}

fn assert_type_mismatch_rejected<S: ZclSchema>(fixture_name: &str) {
    let fixture = fixture(fixture_name);
    for case in &fixture.type_mismatch {
        let wire = type_mismatch_wire(case);
        assert_type_mismatch_case(
            decode_err::<S>(&wire, &format!("{fixture_name}/{}", case.name)),
            case,
            &format!("{fixture_name}/{}", case.name),
        );
    }
}

fn assert_invalid_wire_errors_match_fixture<S: ZclSchema>(fixture_name: &str) {
    let fixture = fixture(fixture_name);
    for case in &fixture.invalid {
        let wire = invalid_wire(case);
        let context = format!("{fixture_name}/{}", case.name);
        assert_zcl_error(
            decode_err::<S>(&wire, &format!("{fixture_name}/{}", case.name)),
            case,
            &context,
        );
    }
}

fn assert_invalid_nullable_errors_match_fixture<S: ZclHasNull>(fixture_name: &str) {
    let fixture = fixture(fixture_name);
    for case in &fixture.invalid {
        let wire = invalid_wire(case);
        let context = format!("{fixture_name}/{} nullable", case.name);
        assert_zcl_error(nullable_decode_err::<S>(&wire, &context), case, &context);
    }
}

