#[derive(Clone, Copy, PartialEq, Debug)]
struct RawBitmap8(u8);
impl ZclBitmap8 for RawBitmap8 {
    fn from_bits(b: u8) -> Self {
        Self(b)
    }
    fn into_bits(self) -> u8 {
        self.0
    }
}

#[derive(Clone, Copy, PartialEq, Debug)]
