macro_rules! enum_compliance {
    ($mod_name:ident, $schema:ty, $raw_helper:ident, $raw_value:ty, $buf_size:expr, $fixture:literal) => {
        mod $mod_name {
            use super::*;

            #[test]
            fn decode_roundtrip() {
                let fixture = fixture($fixture);
                for case in &fixture.roundtrip {
                    let wire = case_wire(case);
                    let expected_raw: $raw_value = case_value(case);
                    let (val, n) = <$schema>::decode(&wire).unwrap_or_else(|e| {
                        panic!("{}/{} decode {:?} → {e:?}", $fixture, case.name, wire)
                    });
                    assert_eq!(val, $raw_helper(expected_raw), "{}/{}", $fixture, case.name);
                    assert_eq!(n, wire.len());
                }
            }

            #[test]
            fn encode_roundtrip() {
                let fixture = fixture($fixture);
                let mut buf = [0u8; $buf_size];
                for case in &fixture.roundtrip {
                    let wire = case_wire(case);
                    let expected_raw: $raw_value = case_value(case);
                    let n = <$schema>::encode($raw_helper(expected_raw), &mut buf).unwrap_or_else(
                        |e| {
                            panic!(
                                "{}/{} encode raw={expected_raw} → {e:?}",
                                $fixture, case.name
                            )
                        },
                    );
                    assert_eq!(&buf[..n], wire.as_slice(), "{}/{}", $fixture, case.name);
                }
            }

            #[test]
            fn null_wire_rejected() {
                let fixture = fixture($fixture);
                for case in &fixture.null_wire {
                    let wire = wire_case(case);
                    assert_eq!(
                        <$schema>::decode(&wire).unwrap_err(),
                        ZclError::NullSentinel,
                        "{}/{}",
                        $fixture,
                        case.name,
                    );
                }
            }

            #[test]
            fn nullable_none_decode() {
                let fixture = fixture($fixture);
                for case in &fixture.null_wire {
                    let wire = wire_case(case);
                    let (val, n) = Nullable::<$schema>::decode(&wire).unwrap();
                    assert!(val.is_none());
                    assert_eq!(n, wire.len());
                }
            }

            #[test]
            fn nullable_none_encode() {
                let fixture = fixture($fixture);
                let mut buf = [0u8; $buf_size];
                for case in &fixture.null_wire {
                    let wire = wire_case(case);
                    let n = Nullable::<$schema>::encode(None, &mut buf).unwrap();
                    assert_eq!(&buf[..n], wire.as_slice());
                }
            }
        }
    };
}

