macro_rules! collection_array_bag_compliance {
    ($mod_name:ident, $coll_schema:ty, $elem_schema:ty, $kind:ty, $fixture:literal) => {
        mod $mod_name {
            use super::*;

            #[test]
            fn decoder_element_values() {
                let fixture = fixture($fixture);
                for case in &fixture.roundtrip {
                    let wire = case_wire(case);
                    let expected_elems = case_values::<$elem_schema>(case);
                    let (coll, n) = <$coll_schema>::decode(&wire).unwrap_or_else(|e| {
                        panic!("{}/{} decode {:?} → {e:?}", $fixture, case.name, wire)
                    });
                    assert_eq!(n, wire.len(), "{}/{}", $fixture, case.name);
                    assert_eq!(
                        coll.len() as usize,
                        expected_elems.len(),
                        "{}/{}",
                        $fixture,
                        case.name
                    );
                    let mut dec = coll.decoder();
                    for (i, &expected) in expected_elems.iter().enumerate() {
                        let val = dec.next().unwrap().unwrap();
                        assert_eq!(val, expected, "{}/{}[{i}]", $fixture, case.name);
                    }
                    assert!(dec.next().is_none());
                    dec.finish().unwrap();
                }
            }

            #[test]
            fn iter_element_values() {
                let fixture = fixture($fixture);
                for case in &fixture.roundtrip {
                    let wire = case_wire(case);
                    let expected_elems = case_values::<$elem_schema>(case);
                    let (coll, _) = <$coll_schema>::decode(&wire).unwrap();
                    let mut i = 0;
                    for result in coll.iter() {
                        let val = result.unwrap();
                        assert_eq!(val, expected_elems[i], "{}/{}[{i}]", $fixture, case.name);
                        i += 1;
                    }
                    assert_eq!(i, expected_elems.len());
                }
            }

            #[test]
            fn encoder_builds_from_scratch() {
                let fixture = fixture($fixture);
                let mut buf = [0u8; 64];
                for case in &fixture.roundtrip {
                    let wire = case_wire(case);
                    let elems = case_values::<$elem_schema>(case);
                    let mut enc = CollectionEncoder::<$kind, $elem_schema>::new(&mut buf)
                        .unwrap_or_else(|e| {
                            panic!("{}/{} encoder new → {e:?}", $fixture, case.name)
                        });
                    for &e in &elems {
                        enc.push(e).unwrap_or_else(|err| {
                            panic!("{}/{} push {e:?} → {err:?}", $fixture, case.name)
                        });
                    }
                    let n = enc
                        .finish()
                        .unwrap_or_else(|e| panic!("{}/{} finish → {e:?}", $fixture, case.name));
                    assert_eq!(&buf[..n], wire.as_slice(), "{}/{}", $fixture, case.name);
                }
            }

            #[test]
            fn null_wire_rejected() {
                let fixture = fixture($fixture);
                for case in &fixture.null_wire {
                    let wire = wire_case(case);
                    assert_eq!(
                        <$coll_schema>::decode(&wire).unwrap_err(),
                        ZclError::NullSentinel,
                        "{}/{}",
                        $fixture,
                        case.name,
                    );
                }
            }

            #[test]
            fn nullable_none_decode() {
                let fixture = fixture($fixture);
                for case in &fixture.null_wire {
                    let wire = wire_case(case);
                    let (val, n) = Nullable::<$coll_schema>::decode(&wire).unwrap();
                    assert!(val.is_none());
                    assert_eq!(n, wire.len());
                }
            }

            #[test]
            fn nullable_none_encode() {
                let fixture = fixture($fixture);
                let mut buf = [0u8; 8];
                for case in &fixture.null_wire {
                    let wire = wire_case(case);
                    let n = Nullable::<$coll_schema>::encode(None, &mut buf).unwrap();
                    assert_eq!(&buf[..n], wire.as_slice());
                }
            }

            #[test]
            fn type_mismatch_rejected() {
                let fixture = fixture($fixture);
                for case in &fixture.type_mismatch {
                    let wire = type_mismatch_wire(case);
                    assert_type_mismatch_case(
                        <$coll_schema>::decode(&wire).unwrap_err(),
                        case,
                        &format!("{}/{}", $fixture, case.name),
                    );
                }
            }

            #[test]
            fn invalid_wire_errors_match_fixture() {
                let fixture = fixture($fixture);
                for case in &fixture.invalid {
                    let wire = invalid_wire(case);
                    let context = format!("{}/{}", $fixture, case.name);
                    assert_zcl_error(<$coll_schema>::decode(&wire).unwrap_err(), case, &context);
                    assert_zcl_error(
                        Nullable::<$coll_schema>::decode(&wire).unwrap_err(),
                        case,
                        &format!("{context} nullable"),
                    );
                }
            }

            #[test]
            fn decoder_finish_rejects_unconsumed_elements() {
                let fixture = fixture($fixture);
                let case = fixture
                    .roundtrip
                    .iter()
                    .find(|case| case.values.len() > 1)
                    .expect("collection fixture should include a multi-element case");
                let wire = case_wire(case);
                let (coll, _) = <$coll_schema>::decode(&wire).unwrap();
                let mut dec = coll.decoder();
                dec.next().unwrap().unwrap();
                assert_eq!(dec.finish().unwrap_err(), ZclError::UnconsumedData);
            }
        }
    };
}

macro_rules! set_compliance {
    ($mod_name:ident, $elem_schema:ty, $policy:ty, $fixture:literal) => {
        mod $mod_name {
            use super::*;

            type Schema = SetOf<$elem_schema, $policy>;

            #[test]
            fn valid_sets_decode_element_values_and_encode() {
                let fixture = fixture($fixture);
                let mut buf = [0u8; 64];
                for case in &fixture.valid {
                    let wire = case_wire(case);
                    let expected_elems = case_values::<$elem_schema>(case);
                    let (coll, n) = Schema::decode(&wire).unwrap_or_else(|e| {
                        panic!("{}/{} decode {:?} → {e:?}", $fixture, case.name, wire)
                    });
                    assert_eq!(n, wire.len());
                    assert_eq!(coll.len() as usize, expected_elems.len());
                    let mut dec = coll.decoder();
                    for (i, &expected) in expected_elems.iter().enumerate() {
                        assert_eq!(
                            dec.next().unwrap().unwrap(),
                            expected,
                            "{}/{}[{i}]",
                            $fixture,
                            case.name
                        );
                    }
                    assert!(dec.next().is_none());
                    dec.finish().unwrap();
                    let written = Schema::encode(coll, &mut buf)
                        .unwrap_or_else(|e| panic!("{}/{} encode → {e:?}", $fixture, case.name));
                    assert_eq!(&buf[..written], wire.as_slice());
                }
            }

            #[test]
            fn encoder_builds_from_scratch() {
                let fixture = fixture($fixture);
                let mut buf = [0u8; 64];
                for case in &fixture.valid {
                    let wire = case_wire(case);
                    let elems = case_values::<$elem_schema>(case);
                    let mut enc =
                        CollectionEncoder::<Set<$policy>, $elem_schema>::new(&mut buf).unwrap();
                    for &e in &elems {
                        enc.push(e).unwrap();
                    }
                    let n = enc.finish().unwrap();
                    assert_eq!(&buf[..n], wire.as_slice(), "{}/{}", $fixture, case.name);
                }
            }

            #[test]
            fn null_wire_rejected() {
                assert_null_wire_rejected::<Schema>($fixture);
            }

            #[test]
            fn nullable_none_decode() {
                assert_nullable_none_decode::<Schema>($fixture);
            }

            #[test]
            fn nullable_none_encode() {
                let mut buf = [0u8; 8];
                assert_nullable_none_encode::<Schema>($fixture, &mut buf);
            }

            #[test]
            fn type_mismatch_rejected() {
                assert_type_mismatch_rejected::<Schema>($fixture);
            }

            #[test]
            fn invalid_wire_errors_match_fixture() {
                assert_invalid_wire_errors_match_fixture::<Schema>($fixture);
                assert_invalid_nullable_errors_match_fixture::<Schema>($fixture);
            }

            #[test]
            fn duplicate_element_rejected() {
                let fixture = fixture($fixture);
                for case in &fixture.duplicate {
                    let wire = wire_case(case);
                    assert_eq!(
                        Schema::decode(&wire).unwrap_err(),
                        ZclError::InvalidValue,
                        "{}/{}",
                        $fixture,
                        case.name
                    );
                }
            }
        }
    };
}

